def sort_list(arr):
    if len(arr) <= 1:
        return arr
    m = len(arr) // 2
    l, r = sort_list(arr[:m]), sort_list(arr[m:])
    res, i, j = [], 0, 0
    while i < len(l) and j < len(r):
        if l[i] <= r[j]:
            res.append(l[i])
            i += 1
        else:
            res.append(r[j])
            j += 1
    return res + l

